def reframe_thought(negative_thought):
    distortions = {
        "all_or_nothing": ["always", "never", "every", "none"],
        "overgeneralization": ["everything", "everyone"],
        "catastrophizing": ["worst", "disaster", "awful"]
    }

    reframed_thought = negative_thought

    for distortion_type, keywords in distortions.items():
        for keyword in keywords:
            if keyword in negative_thought.lower():
                reframed_thought = negative_thought.replace(keyword, "sometimes")
                break

    return reframed_thought

# Example usage:
user_thought = "I always fail at my tasks and never do anything right."
reframed = reframe_thought(user_thought)
print(f"Original thought: {user_thought}")
print(f"Reframed thought: {reframed}")

This function identifies common cognitive distortion keywords in a negative thought and replaces them with more balanced language, demonstrating a basic CBT reframing technique.
